#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 50

int minClicks(char grid[][MAX], int R, int C) {
    int clicks = 0;
    int i, j;
    for (i = 0; i < R; i++) {
        for (j = 0; j < C; j++) {
            if (grid[i][j] == '*') {
                clicks++;
            }
        }
    }
    return clicks;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int R, C;
        scanf("%d %d", &R, &C);
        char grid[R][MAX];
        int i;
        for (i = 0; i < R; i++) {
            scanf("%s", grid[i]);
        }
        printf("%d\n", minClicks(grid, R, C));
    }
    return 0;
}

